"""
MKT Christ Commentary — Luke chapter 24
Run: python3 scripts/zc-christ-luke-24-24.py

Source data used:
- data/interlinear/luke.json
- data/translation/draft/mediating/luke.json
- data/commentary/mkt-christ/luke.json (v27, v46 already present — preserved)

Key decisions in this range:
- Empty tomb (vv.1-12): first day of the week = new creation first-day pattern; women as chosen
  first witnesses reverses cultural hierarchy of credibility (deliberate Christological choice)
- Emmaus (vv.13-35): Christological hermeneutic — word (vv.25-27) + sacrament (v.30) together
  produce recognition; "burning hearts" (v.32) is Luke's model for Spirit-mediated encounter
- Fourfold eucharistic action (v.30) mirrors Last Supper (22:19) and feeding of 5000 (9:16)
- Physical resurrection body (vv.39-43): wounds remain in risen body (Rev 5:6); eating of fish
  is bodily verification, not incidental detail
- v.44: three-fold OT division (Law/Prophets/Psalms) = entire canon is Christocentric
- Ascension (vv.50-53): priestly blessing posture (Lev 9:22; Num 6:24-26) + Dan 7:13-14
  enthronement + Ps 110:1; worship of ascending Christ is implicit deity-declaration
- Luke's temple-framing: Gospel opens (1:5-23 Zechariah) and closes (v.53 disciples praising)
  in the temple — the whole narrative is the fulfillment of what the temple promised
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: merge new entries without overwriting any existing verse
    # CHANGE? If output path changes, update load_comm/save_comm source arg
    # VERIFY: re-run; spot-check v30 (eucharistic action), v51 (ascension), v53 (temple close)
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE_24 = {
  "24": {
    "1": '<p>A direct fulfillment: "on the first day of the week, very early in the morning" — the resurrection happens on the first day, the new creation\'s inaugural morning. The seventh-day Sabbath (23:56) has passed; the eighth day / first day is the day of new creation in early Jewish and Christian thought (the church\'s worship shifted from the seventh to the first day precisely because of the resurrection). The women who kept the Sabbath in faithful Torah-obedience are the first to encounter the new order that supersedes it.</p>',
    "2": '<p>A revelation of God: the stone rolled away from the tomb is the defeat of the combined seal of Roman imperial authority (Matthew 27:66 notes the Roman seal) and Jewish religious power over death. The Romans could not contain him; the stone that was the symbol of finality — the same stone that sealed the prophets\' tombs — has been moved by divine power. The passive "rolled away" (apokekulismenon) is the divine passive: God rolled it away, as he parted the sea and opened prison doors (Acts 12:10) throughout Israel\'s history.</p>',
    "3": '<p>A direct proclamation: "they did not find the body of the Lord Jesus." Luke\'s first use of the full confessional title "the Lord Jesus" (ton kurion Iēsoun) at the resurrection is deliberate: the one who died as the condemned criminal of 23:33 is now addressed with the earliest Christological confession (Acts 2:36, "God has made him both Lord and Christ"). The empty tomb is not the resurrection but its necessary condition and first evidence; the physical absence of the body is the starting point of resurrection faith.</p>',
    "4": '<p>A direct fulfillment: the two men in gleaming clothes (astraptoush&#257;) are angelic witnesses whose appearance echoes the Transfiguration (9:29-31), where Moses and Elijah appeared "in glory" to witness to Christ\'s coming "departure" (exodus). The two-witness requirement of Deuteronomy 19:15 (establishing a fact by two or three witnesses) is applied by Luke: the resurrection is attested by angelic testimony as well as the empty tomb and the post-resurrection appearances. The gleaming robes signal the divine realm from which they come.</p>',
    "5": '<p>A direct revelation: "Why do you look for the living among the dead?" — the angelic question reframes the entire search. "The living one" (ton z&#333;nta) is a divine title in Revelation 1:18 ("I am the living one; I died, and behold I am alive forevermore"). Christ is not merely resuscitated but possesses resurrection life — the uncreated life that belongs to God. The women were looking for a corpse; they are redirected to the one who holds life in himself (John 5:26, "the Father has granted the Son to have life in himself").</p>',
    "6": '<p>A direct fulfillment: "He is not here; he has risen!" (ēgerthē) — the divine passive: God raised him, as the entire OT pattern predicted (Ps 16:10, "you will not abandon my soul to Sheol, or let your holy one see corruption" — cited in Acts 2:27). "Remember how he told you while he was still in Galilee" activates the disciples\' memory of the Christological predictions; the resurrection is not a surprise to the cosmic plan, only to the disciples who had failed to hold the predictions together with the crucifixion they had witnessed.</p>',
    "7": '<p>A direct fulfillment: the angel\'s citation of Christ\'s own passion-resurrection prediction (9:22, 18:31-33) as now fulfilled establishes the resurrection as the completion of the divine program announced from the beginning of the journey to Jerusalem. The <em>dei</em> (must) is divine necessity: suffering → death → third-day resurrection is the Christological arc not improvised in the crisis but planned from eternity and predicted from Galilee. The Son of Man who predicted his own death is the same one who predicted his own resurrection — and both predictions are now fulfilled.</p>',
    "8": '<p>A revelation of God: "they remembered his words" — the act of remembering is the first movement of resurrection faith. Christ\'s word, spoken before the passion and held in the disciples\' memory through it, now illuminates the event they have just encountered. The Spirit\'s role in resurrection faith is the role of the faithful memory: John 14:26 promises that "the Holy Spirit will teach you all things and bring to your remembrance all that I said to you." The word that preceded the death interprets the empty tomb.</p>',
    "9": '<p>A direct revelation: the women\'s testimony to the Eleven and "to all the others" is the first proclamation of the resurrection — the prōtē kerygma. The witnesses are the women who had followed from Galilee (23:55), the same ones who watched the crucifixion (23:49) and saw the burial (23:55). Their continuous eyewitness presence from death to empty tomb is Luke\'s apologetic chain: the same witnesses who confirmed the death are now confirming the resurrection. The first preachers of the resurrection were women.</p>',
    "10": '<p>A revelation of God: Luke names the women witnesses — Mary Magdalene, Joanna, Mary the mother of James — in a context where women\'s legal testimony was discounted in first-century culture. The risen Christ\'s choice of women as his first resurrection witnesses reverses the cultural hierarchy of credibility in the same pattern as the Gospel\'s recurring reversals (the poor blessed, the humble exalted). The Christ who was born of a woman (1:35), who restored women throughout his ministry, continues to honor women at the resurrection\'s first dawn.</p>',
    "11": '<p>A revelation of God: the apostles\' dismissal of the women\'s report as "nonsense" (l&#275;ros, medical term for feverish babbling) is Luke\'s apologetic gift: the resurrection was not generated by credulous disciples who wished it into being. The Eleven actively disbelieved the first testimony. The subsequent transformation of these same disbelievers into witnesses who proclaimed the resurrection at the cost of their lives is the historical puzzle that the resurrection itself best explains. Their initial skepticism strengthens rather than weakens the testimony of their later conviction.</p>',
    "12": '<p>A revelation of God: Peter\'s run to the tomb — seeing only the linen strips lying by themselves — is the disciple poised at the threshold of resurrection faith. The linen strips alone (no body, no grave-robber\'s disarray) are the physical evidence that no ordinary explanation accounts for. Peter goes away "amazed" (thaumazōn) — suspended between his memory of the predictions, the evidence of the empty tomb, and his guilt over the denial. The resurrection will encounter him in the appearance of v.34 and restore what the denial broke.</p>',
    "13": '<p>A revelation of God: the risen Christ appears not first to the apostolic leadership but to two unnamed, otherwise insignificant disciples walking away from Jerusalem in defeat. The pattern of the seeking Christ reaching the margins — the lost sheep, Zacchaeus, the prodigal — continues beyond the resurrection. The risen Christ goes where the discouraged and disappointed are, not only where the faithful have gathered. The Emmaus road is the resurrection\'s pastoral mission to the church\'s walking-away members.</p>',
    "14": '<p>A revelation of God: the disciples\' conversation about "everything that had happened" is the raw material the risen Christ enters. He does not wait for the disciples to have reached a correct theological conclusion before appearing; he joins their confused, grieving discussion. The incarnation of the risen Christ into human conversation is an extension of the pattern throughout Luke: Christ went where people were, not where they should be. The Emmaus road is a model of how the risen Christ meets the church — in the middle of its struggling questions.</p>',
    "15": '<p>A direct revelation: "Jesus himself came up and walked along with them" — the risen Christ\'s self-initiation is the consistent Lukan pattern: the seeking Savior (Luke 19:10, "the Son of Man came to seek and to save the lost"). He did not wait to be sought; he approached. The risen Christ continues the same mission as the incarnate Christ — entering the road where the confused are walking, joining the journey, initiating the encounter that will transform it.</p>',
    "16": '<p>A revelation of God: "they were kept from recognising him" (ekratounto tou m&#275; epign&#333;nai auton) — the divine passive restraint on recognition is not deception but pedagogy. The risen Christ will be recognized through the word (vv.25-27) and the sacrament (v.30), not through physical appearance alone. Luke\'s point is that the resurrection body is recognizable but not automatically recognized; faith requires the interpretive gift of the word and the sacramental act, not merely the encounter. The church\'s recognition of the risen Christ in worship follows the Emmaus pattern.</p>',
    "17": '<p>A revelation of God: the risen Christ asks "What are you discussing?" not because he lacks the information but because drawing out grief is the beginning of healing it. "They stood still, their faces downcast" (skythropoi) — the posture of defeated hope. The risen Christ does not rebuke their grief but enters it; he becomes a fellow-traveler in their sorrow before he reveals that the sorrow is unfounded. The pastoral Christ who wept at Lazarus\'s tomb (John 11:35) still enters human grief at the resurrection.</p>',
    "18": '<p>A revelation of God: Cleopas\'s question — "Are you the only stranger in Jerusalem who does not know the things that have happened?" — is Luke\'s greatest irony. The only one in all Jerusalem who truly understands what happened is the stranger they address as ignorant. Christ is always the one who knows the meaning of events from the inside; the disciples report the facts to the one who is the fact. The question inverts the epistemological relationship: the ignorant disciples are instructing the all-knowing Lord.</p>',
    "19": '<p>A theme: the Emmaus disciples\' summary of Jesus as "a prophet, powerful in word and deed before God and all the people" is a true but partial Christology. It corresponds to Moses\'s prophecy of "a prophet like me" (Deut 18:15-18), which Peter will cite in Acts 3:22-23 as fulfilled in Jesus. The disciples have the prophet-category correct but have not yet grasped what kind of prophet — one who is greater than Elijah and Elisha (Luke 7:16), greater than Jonah and Solomon (11:31-32), and ultimately the Son of God, not merely a prophet. The Emmaus road moves them from prophet to Lord.</p>',
    "20": '<p>A theme: the disciples\' accurate summary of the passion — "the chief priests and our rulers handed him over to be sentenced to death, and they crucified him" — reports the facts without yet the interpretive framework. The raw passion-history is the datum that the risen Christ will now interpret from the Scriptures. The Emmaus disciples know what happened; they do not yet know what it means. The resurrection reveals not new facts but the meaning of the fact they already know.</p>',
    "21": '<p>A direct revelation: "we had hoped that he was the one who was going to redeem Israel" (lytrousthai ton Israēl) uses the Exodus-liberation vocabulary of the Benedictus (Luke 1:68, lytr&#333;sin — he has visited and redeemed his people). The hope was not wrong; it has been fulfilled — but through the cross, not through political deliverance. The disciples\' disappointment is the classic misreading of OT prophecy that reads liberation as political without grasping the deeper liberation from sin that Isa 53 and Jer 31 promised. The risen Christ will show them that the redemption happened precisely in what seemed to defeat it.</p>',
    "22": '<p>A revelation of God: the women\'s report ("some of our women amazed us") becomes the bridge in the disciples\' narrative that the risen Christ will confirm. Their testimony, dismissed by the Eleven (v.11), is now being reported by confused disciples to the one who is alive. The chain of testimony — women, empty tomb, angelic message — is all accurate; it only lacks the interpretive framework that the risen Christ is about to supply.</p>',
    "23": '<p>A revelation of God: the report of the angelic message — "he was alive" (z&#275;n auton) — is now spoken by the confused disciples to the living one himself. Luke\'s narrative irony reaches its peak: the resurrection report is delivered to the risen Christ. The words "he was alive" are true beyond what the Emmaus disciples know; they are speaking better than they understand, as so many in Luke\'s Gospel do (Caiaphas\'s unwitting prophecy, Pilate\'s superscription, the soldiers\' mock-royal investiture).</p>',
    "24": '<p>A revelation of God: the verification of the empty tomb by some disciples confirms the chain of testimony that Luke 1:1-4 promised to provide — "eyewitnesses and ministers of the word" who handed on what they had seen. The empty tomb is confirmed; the body is absent; the risen Christ is not yet seen by the disciples who went. But the physical evidence is established before the appearances. Luke\'s resurrection account builds from evidence (empty tomb, linen strips) to testimony (angelic, then apostolic) to encounter (Emmaus, Jerusalem appearances).</p>',
    "25": '<p>A direct revelation: "How foolish you are, and how slow to believe all that the prophets have spoken!" — the risen Christ\'s rebuke is not cruelty but urgent pastoral instruction. "All that the prophets have spoken" (tois prophetais) is the comprehensive claim: not selected messianic proof-texts but the whole prophetic witness speaks to the Messiah\'s suffering and glory. The Emmaus disciples\' failure is not ignorance of facts but failure to read the Scriptures as a whole; they had isolated the suffering-servant passages from the glory-passages and vice versa.</p>',
    "26": '<p>A direct revelation: "Did not the Messiah have to suffer these things and then enter his glory?" — the <em>dei</em> of divine necessity governs the Christological arc: suffering → glory. The OT had established exactly this pattern: the Servant of Isaiah 52:13-53:12 (humiliated, but then "high and lifted up"); the Son of Man of Daniel 7 (given the kingdom after the suffering described in Daniel 7:19-27); the righteous sufferer of Psalm 22 (the cry of dereliction, then the vindication in vv.22-31). The cross and resurrection are not two separate events but one divine movement: through the cross to the glory.</p>',
    "28": '<p>A revelation of God: the risen Christ\'s gesture of "continuing on as if going further" is the invitation for the disciples to urge him to stay. The risen Christ does not impose himself; he waits to be received. The pattern is consistent with his ministry: he passed by Zacchaeus\'s tree; he had nowhere to lay his head; he came where he was invited. The hospitality context of the Emmaus meal — the disciples invite the stranger in — is the condition for the self-disclosure that follows. Christ makes himself known to those who open their homes and their hearts.</p>',
    "29": '<p>A revelation of God: "Stay with us, for it is nearly evening; the day is almost over" — the invitation is the church\'s foundational prayer to the risen Christ, anticipating John 15:4-5 ("abide in me, and I in you"). The disciples\' urgency ("the day is almost over") reflects their unrecognized need: they are in the twilight of incomplete understanding, and the light of Christ\'s presence is what they need without yet knowing it is what they have. The Emmaus supper begins with this invitation — the church\'s Eucharist begins with the same hospitality.</p>',
    "30": '<p>A direct fulfillment: the fourfold eucharistic action — "he took bread, gave thanks, broke it, and began to give it to them" — exactly mirrors the institution of the Lord\'s Supper (Luke 22:19: "taking bread, giving thanks, breaking it, giving") and the feeding of the five thousand (9:16: "taking the five loaves, looking to heaven, blessing, breaking, giving"). The Emmaus meal is the risen Christ\'s eucharistic self-revelation: the one who gave himself as bread at the Last Supper gives himself again at the first post-resurrection table. Every Eucharist the church celebrates is the ongoing Emmaus meal — the risen Christ making himself known in the breaking of the bread.</p>',
    "31": '<p>A direct revelation: "their eyes were opened and they recognized him" — the <em>dianoig&#333;</em> (to open fully, as of eyes) is the resurrection gift. Recognition (epegrisan) requires both the word of Christ from the Scriptures (vv.25-27) and the sacramental action at the table (v.30). Luke\'s theology of encounter with the risen Christ requires both; neither the scriptural exposition alone nor the meal alone produces recognition. The church encounters the risen Christ in the same dual way: through the preached word and the broken bread — word and sacrament together open the eyes. Then "he disappeared from their sight" — the risen Christ is present but not visible; his presence henceforth is through word and sacrament, not through unmediated vision.</p>',
    "32": '<p>A revelation of God: "Were not our hearts burning within us while he talked with us on the road and opened the Scriptures to us?" — the retrospective recognition of Christ\'s presence through the burning-heart experience is Luke\'s model for Spirit-mediated encounter with the risen Christ. The burning heart (<em>kaiomenē ēn</em>) is not mere emotional warmth but the deep inner movement of genuine encounter — the same fire as the Spirit\'s tongues at Pentecost (Acts 2:3). Scripture interpreted by Christ through the Spirit produces not intellectual assent but transformative inner illumination. The church knows the risen Christ through this burning.</p>',
    "33": '<p>A revelation of God: the disciples immediately reversed direction — from Emmaus (away from Jerusalem, away from the cross) back to Jerusalem (toward the apostolic community, toward the commission). Resurrection encounters create community: the isolated disciples must return to the gathered witnesses. The same movement will define Acts: the Spirit drives the community outward from Jerusalem to the world, but it is always Jerusalem — the community of resurrection witnesses — from which the mission departs. Resurrection faith is not private; it compels community.</p>',
    "34": '<p>A direct fulfillment: "The Lord has risen and has appeared to Simon" — the community\'s confession before the Emmaus disciples report their experience establishes the apostolic priority of the resurrection appearance to Peter (Cephas in 1 Cor 15:5, where Paul lists it first in the appearance sequence). The appearance to Peter is the restoration of the one who denied three times; the risen Christ restores the denier first, before the other apostles, as an act of grace that anticipates the pattern of Acts where Peter preaches first at Pentecost. The resurrection restores precisely those whom the passion shattered.</p>',
    "35": '<p>A revelation of God: the Emmaus disciples\' summary — Jesus "was recognized by them in the breaking of the bread" — establishes the eucharistic meal as the primary ongoing locus of post-resurrection encounter with the risen Christ. Acts 2:42 describes the Jerusalem community as devoted to "the apostles\' teaching, the fellowship, the breaking of bread, and the prayers" — the Emmaus pattern writ large. The church will recognize the risen Christ in exactly the way the Emmaus disciples did: through scriptural exposition and the shared table. The Emmaus road is the church\'s permanent pattern of encountering the risen Lord.</p>',
    "36": '<p>A direct fulfillment: "Peace be with you" (<em>eirēnē hymin</em>) — the risen Christ\'s shalom-greeting is the new covenant peace of Isaiah 54:10 ("my covenant of peace shall not be removed") and Ezekiel 37:26 ("I will make a covenant of peace with them") now enacted in his person. The peace he gives is not the absence of conflict but the presence of the one who made peace through his blood (Col 1:20). The risen Christ speaks peace into the community that has been shattered by his death — the same word that stilled the storm (8:24) now stills the disciples\' fear.</p>',
    "37": '<p>A revelation of God: the disciples\' fear and ghost-hypothesis is Luke\'s apologetic against spiritualized resurrection. The community that will preach the resurrection to a skeptical world is itself initially skeptical; their resistance to the ghost interpretation comes only through the physical self-revelation of the risen Christ (vv.38-43). The risen Christ is not a shade (shede), a ghost (pneuma), or a vision (horama) — he has flesh and bones; he eats; he can be touched. Luke preserves the disciples\' incredulity to make the point: the resurrection is not the projection of wishful thinking but the encounter with unexpected physical reality.</p>',
    "38": '<p>A revelation of God: "Why do doubts (<em>dialogismoi</em>) arise in your minds?" — the word for doubts appears elsewhere in Luke for the hostile inner thoughts of Pharisees and scribes (5:22, 6:8) whom Jesus perceived and addressed. The risen Christ reads the interior state of the disciples as he read the interior state of his opponents. The same Lord who knew what was in people throughout his ministry (John 2:25) knows what is in the disciples now. The risen Christ addresses not the surface behavior but the heart\'s doubt, the same way he addressed hearts throughout his earthly ministry.</p>',
    "39": '<p>A direct revelation: "Look at my hands and my feet. It is I myself! Touch me and see; a ghost does not have flesh and bones, as you see I have." The bodily resurrection is the central Christological claim. The invitation to touch establishes that the risen body is physical — not resuscitated mortality but transformed embodiment. The wounds remain in the risen body (hands and feet = the crucifixion marks), not as defects but as permanent identification: Revelation 5:6 sees the Lamb "standing as though it had been slain." The crucified and the risen are the same one; the wounds in glory are the eternal testimony to the atonement.</p>',
    "40": '<p>A direct revelation: "he showed them his hands and feet" — the showing of the wounds is the embodied declaration of Christological identity. Thomas\'s later request (John 20:27, "put your finger here, and see my hands; and put out your hand, and place it in my side") and this Lukan moment together establish that the risen Christ carries the marks of the passion permanently into resurrection. The wounds are not healed in the sense of being removed; they are glorified — the suffering that accomplished atonement is inscribed on the body of the triumphant Lord.</p>',
    "41": '<p>A revelation of God: "they still did not believe it because of joy and amazement" — disbelief from excess joy rather than grief. The disciples cannot process the resurrection because it is better than what they had allowed themselves to hope for. The pastoral Christ addresses this incredulity with the same patient self-disclosure he used for the Emmaus disciples: physical evidence (v.39-40), then shared meal (vv.42-43). The risen Christ meets each form of unbelief with the particular evidence each form needs; joy-disbelief receives the same patient engagement as grief-disbelief.</p>',
    "42": '<p>A revelation of God: the giving of a piece of broiled fish is the ordinariness of the resurrection encounter. The risen Christ eats the everyday food of Galilean fishermen — the same food the disciples ate on the sea. The physicality is deliberate: no symbolic meal, no sacred food, just broiled fish from the common store. Luke\'s insistence on physical ordinariness within the extraordinary is his counter to both spiritualized resurrection (no body) and spectacular proof (miraculous food). The risen Lord eats fish. The body is real.</p>',
    "43": '<p>A direct revelation: "he took it and ate it in their presence" — the risen Christ\'s eating is the bodily verification that the incarnation did not dissolve at death. The one who at the Last Supper said "I will not eat again until the kingdom of God comes" (22:16, 18) now eats in the community that the resurrection inaugurates. The kingdom has come in his risen person; the promise of the table in the kingdom (22:30, "you will eat and drink at my table in my kingdom") has begun its fulfillment. The risen Christ eating fish with his disciples is the firstfruits of the eschatological feast.</p>',
    "44": '<p>A direct fulfillment: "everything must be fulfilled that is written in the Law of Moses, the Prophets, and the Psalms about me" — the three-fold division of the Hebrew Bible (Torah, Nevi\'im, Ketuvim) invoked as a complete whole. The risen Christ claims that the entire OT canon is Christocentric; not selected proof-texts but the full structure of the Law (types and shadows), the Prophets (prediction and pattern), and the Psalms (the laments and praises of the righteous sufferer and his vindication) are all about him. The <em>dei</em> (must be fulfilled) grounds this in divine necessity, not post-hoc proof-texting.</p>',
    "45": '<p>A revelation of God: "he opened their minds so they could understand the Scriptures" — the <em>dianoig&#333;</em> (opening) applied to minds in v.45 is the same verb used for opened eyes in v.31. The risen Christ performs the same epistemological gift at both points: recognition of his presence in the eucharist and understanding of his presence in Scripture both require his own action on the reader. The hermeneutic of reading the OT as about Christ is not a technique that can be learned academically; it is a capacity given by the risen Christ through the Spirit (John 16:13-14). Without this opening, the Scripture remains opaque to its own central referent.</p>',
    "47": '<p>A direct fulfillment: "repentance for the forgiveness of sins will be preached in his name to all nations" — the missionary commission flows from the resurrection (vv.34-46) to the universal proclamation. The forgiveness won at the cross ("Father, forgive them," 23:34) is now to be proclaimed in the name of the crucified-and-risen Christ to all nations — the Isaianic Servant mission (Isa 49:6, "a light to the Gentiles, that my salvation may reach to the end of the earth") enacted through the community. The Gentile mission of Acts is the narrative of this commission being fulfilled from Jerusalem to Rome.</p>',
    "48": '<p>A direct revelation: "You are witnesses of these things" — the formal commissioning of the disciples as <em>martyres</em> (witnesses, the root of "martyr"). The witness is not merely to a doctrine but to events: they have witnessed the crucifixion (from a distance, 23:49), encountered the risen Christ (vv.36-43), heard his scriptural interpretation (vv.44-46), and received the commission. Acts 1:8 will repeat and extend: "you will be my witnesses in Jerusalem, in all Judea and Samaria, and to the ends of the earth." The witness-chain that began with the women at the tomb passes through the Eleven to the entire church.</p>',
    "49": '<p>A direct revelation: "I am going to send you what my Father has promised" — the promise of the Father is the Spirit, the fulfillment of Joel 2:28-29 ("I will pour out my Spirit on all flesh") that Peter will proclaim at Pentecost (Acts 2:17-21). The risen Christ sends the same Spirit who overshadowed Mary at the conception (1:35), descended on Jesus at his baptism (3:22), and drove him through the wilderness (4:1-2) — the Spirit of the entire Christ-event now given to the entire community. The disciples are to wait in Jerusalem until they are "clothed with power from on high" — the Spirit is the power of the resurrection mission.</p>',
    "50": '<p>A direct fulfillment: the ascending Christ who "lifted up his hands and blessed them" assumes the priestly posture of Aaron after the first tabernacle service (Lev 9:22, "Aaron lifted up his hands toward the people and blessed them") and the Aaronic blessing of Numbers 6:24-26. The risen Christ ascends as the Great High Priest in the act of blessing his people — which Hebrews 7:25 confirms is his permanent posture: "he always lives to make intercession for them." The ascension is not departure but installation into the intercessory ministry from which the risen Christ blesses the church in perpetuity.</p>',
    "51": '<p>A direct fulfillment: "he left them and was taken up into heaven" — the Ascension is the fulfillment of Daniel 7:13-14, where "one like a son of man came with the clouds of heaven" to the Ancient of Days and received "dominion and glory and a kingdom." Acts 1:9-11 provides the fuller account (the cloud, the two angels, the promise of return in the same manner); Luke 24:51 is the summary statement. The Ascension is not merely departure but enthronement: at the Father\'s right hand (Ps 110:1, the verse Jesus cited most frequently as Christologically definitive) the risen Christ is invested with the universal authority he will exercise until "all enemies are put under his feet" (1 Cor 15:25).</p>',
    "52": '<p>A direct revelation: "they worshipped him" (<em>proskunēsantes</em>) — the disciples\' worship of the ascending Christ is the climactic Christological declaration of Luke\'s Gospel. In Jewish practice and in Jesus\'s own teaching (4:8, "worship the Lord your God and serve him only"), <em>proskyneō</em> was reserved for God alone. The disciples\' uninhibited worship of the ascending Jesus is the implicit declaration of his deity — the same declaration that will become explicit in the church\'s earliest Christological hymns (Phil 2:9-11, "every knee shall bow... to the glory of God the Father"). The joy (chara megalē) that accompanies their worship is the joy of those who know the ascended Christ is not absent but enthroned, interceding, and returning.</p>',
    "53": '<p>A revelation of God: "they stayed continually at the temple, praising God" — the Gospel that opened in the temple (1:5-23, Zechariah\'s vision and the announcement of the forerunner) closes in the temple with the disciples\' praise. Luke\'s careful temple-framing (temple → temple) declares that the entire Gospel is the fulfillment of what the temple promised: the presence of God with his people, the meeting place of heaven and earth, the sacrificial system that atoned for sin. But the disciples in the temple are not offering animal sacrifices — they are praising God. The new worship born of the resurrection has superseded the old sacrificial worship; the fullness of what the temple shadowed is now resident in the community of the risen Christ, waiting for the Spirit who will constitute them as the new temple (1 Cor 3:16; 6:19).</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'luke')
    merge_comm(existing, LUKE_24)
    save_comm('mkt-christ', 'luke', existing)
    ch24_count = len(existing.get('24', {}))
    print(f'Luke 24 mkt-christ: {ch24_count} verses written.')

if __name__ == '__main__':
    main()
